/// <reference types="express" />

declare module "istanbul-middleware" {
    import * as express from "express";

    type Matcher = (file: string) => boolean;
    type PostLoadHookFn = (file: any) => {};
    type PostLoadHook = (matcherfn: Matcher, transformer: any, verbose: boolean) => PostLoadHookFn;

    export function hookLoader(matcherOrRoot: Matcher | string, opts?: {
        postLoadHook?: PostLoadHook | undefined;
        verbose?: boolean | undefined;
        // and istanbul.Instrumenter(...opts)
    }): void;

    export function createHandler(opts?: {
        resetOnGet?: boolean | undefined;
    }): any;

    type ClientMatcher = (req: express.Request) => boolean;
    type PathTransformer = (req: express.Request) => string;

    export function createClientHandler(root: string, opts?: {
        matcher?: ClientMatcher | undefined;
        pathTransformer?: PathTransformer | undefined;
        verbose?: boolean | undefined;
    }): any;
}

declare namespace Express {
    export interface Response {
        jsend: jsend.jsendExpress;
    }
}

declare namespace jsend {
    interface JSendObject {
        status: string;
        code?: number | undefined;
        data?: any;
        message?: string | undefined;
    }

    interface jsendCore {
        success(data: Object | null): JSendObject;
        fail(data: Object): JSendObject;
        error(message: string | { message: string; code?: number | undefined; data?: Object | undefined }): JSendObject;
    }

    interface jsendExpress extends jsendCore {
        (err: string | Object, json?: Object): void;
    }

    interface jsend extends jsendCore {
        isValid(json: Object): boolean;
        forward(json: Object, done: (err: any, data: any) => any): void;
        fromArguments(err: string | Object, json?: Object): JSendObject;
        middleware(req: any, res: any, next: Function): any;
    }

    interface jsendExport extends jsend {
        (config?: { strict: boolean }, host?: Object): jsend;
    }
    var jsend: jsendExport;
}

declare module "jsend" {
    export = jsend.jsend;
}

/// <reference types="node"/>

import { IncomingMessage, Server, ServerResponse as HttpServerResponse } from "http";
import { RequestHandler } from "micro";
import UrlPattern = require("url-pattern");

export type ServerResponse = HttpServerResponse;
export type ServerRequest = IncomingMessage & {
    params: { [key: string]: string };
    query: { [key: string]: string };
};
export type AugmentedRequestHandler = (
    req: ServerRequest,
    res: ServerResponse,
) => any;

export type RouteHandler = (path: string | UrlPattern, handler: AugmentedRequestHandler) => RequestHandler;

export function router(...routes: RequestHandler[]): RequestHandler;
export function withNamespace(namespace: string): (...routes: RequestHandler[]) => RequestHandler;

export const get: RouteHandler;
export const post: RouteHandler;
export const put: RouteHandler;
export const patch: RouteHandler;
export const del: RouteHandler;
export const head: RouteHandler;
export const options: RouteHandler;
